import stylesText from './exercise-session-card.css?inline';
import { cssStyleSheet } from '../../../utils/css.js';
import type { Exercise, StrengthSet } from '@motivation/shared';
import {
    HEALTH_EVENTS,
    type StrengthSetCompleteEvent,
    createExerciseRemoveFromSessionEvent,
    createStrengthSetAddRequestEvent,
} from '../health-events.js';
import '../strength-set-row/strength-set-row.component.js';
import type { StrengthSetRow } from '../strength-set-row/strength-set-row.component.js';
import '../rest-timer/rest-timer.component.js';
import type { RestTimer } from '../rest-timer/rest-timer.component.js';

const styles = cssStyleSheet(stylesText);

const template = document.createElement('template');
template.innerHTML = `
    <div class="card" part="card">
        <div class="card__header">
            <h3 class="card__title"></h3>
            <button class="card__remove" type="button">Remove exercise</button>
        </div>
        <div class="sets-list" part="sets-list"></div>
        <div class="card__footer">
            <button class="add-set-btn" type="button">+ Add set</button>
            <rest-timer></rest-timer>
        </div>
    </div>
`;

/**
 * Groups all `strength_sets` rows for one exercise inside a workout session.
 * Owns the rest timer near the next pending set — listens to its own rows'
 * STRENGTH_SET_COMPLETE event and starts the timer with the set's `rest_s`.
 */
export class ExerciseSessionCard extends HTMLElement {
    private exerciseValue: Exercise | null = null;
    private setsValue: StrengthSet[] = [];
    private previousByExercise: StrengthSet[] = [];
    private titleNode!: HTMLElement;
    private setsList!: HTMLElement;
    private addBtn!: HTMLButtonElement;
    private removeBtn!: HTMLButtonElement;
    private restTimer!: RestTimer;

    constructor() {
        super();
        const shadow = this.attachShadow({ mode: 'open' });
        shadow.adoptedStyleSheets = [styles];
        shadow.appendChild(template.content.cloneNode(true));
        this.titleNode = shadow.querySelector('.card__title') as HTMLElement;
        this.setsList = shadow.querySelector('.sets-list') as HTMLElement;
        this.addBtn = shadow.querySelector('.add-set-btn') as HTMLButtonElement;
        this.removeBtn = shadow.querySelector('.card__remove') as HTMLButtonElement;
        this.restTimer = shadow.querySelector('rest-timer') as RestTimer;

        // Listeners on own shadow DOM — attach once in the constructor so a
        // disconnect/reconnect cycle doesn't double-bind them. No cleanup
        // needed because the listener targets live and die with this element.
        this.addBtn.addEventListener('click', () => this.emitAddSet());
        this.removeBtn.addEventListener('click', () => this.emitRemoveExercise());
        this.setsList.addEventListener(HEALTH_EVENTS.STRENGTH_SET_COMPLETE, (e: StrengthSetCompleteEvent) => {
            const restSeconds = e.detail.rest_s ?? 0;
            if (restSeconds > 0) this.restTimer.start(restSeconds);
        });
    }

    set exercise(value: Exercise) {
        this.exerciseValue = value;
        this.render();
    }

    get exercise(): Exercise | null {
        return this.exerciseValue;
    }

    set sets(value: StrengthSet[]) {
        this.setsValue = [...value].sort((a, b) => a.set_index - b.set_index);
        this.renderSets();
    }

    /** Recent strength_sets for this exercise across past sessions — feeds the prev column. */
    set previousSets(value: StrengthSet[]) {
        this.previousByExercise = value;
        this.renderSets();
    }

    connectedCallback(): void {
        this.render();
    }

    private render(): void {
        if (!this.exerciseValue) return;
        this.titleNode.textContent = this.exerciseValue.display_name;
        this.renderSets();
    }

    private renderSets(): void {
        if (!this.exerciseValue) return;
        // Match a previous set by set_index — most useful "did the same set last time?" prefill.
        const previousByIndex = new Map<number, StrengthSet>();
        for (const prev of this.previousByExercise) {
            if (!previousByIndex.has(prev.set_index)) {
                previousByIndex.set(prev.set_index, prev);
            }
        }

        this.setsList.replaceChildren(...this.setsValue.map((set) => {
            const row = document.createElement('strength-set-row') as StrengthSetRow;
            row.set = set;
            row.previousSet = previousByIndex.get(set.set_index) ?? null;
            return row;
        }));
    }

    private emitAddSet(): void {
        if (!this.exerciseValue) return;
        this.dispatchEvent(createStrengthSetAddRequestEvent({ exercise_id: this.exerciseValue.id }));
    }

    private emitRemoveExercise(): void {
        if (!this.exerciseValue) return;
        this.dispatchEvent(createExerciseRemoveFromSessionEvent({ exercise_id: this.exerciseValue.id }));
    }
}

if (!customElements.get('exercise-session-card')) {
    customElements.define('exercise-session-card', ExerciseSessionCard);
}
