import stylesText from './rest-timer.css?inline';
import { cssStyleSheet } from '../../../utils/css.js';
import { createRestTimerFinishEvent } from '../health-events.js';

const styles = cssStyleSheet(stylesText);

const template = document.createElement('template');
template.innerHTML = `
    <div class="rest-timer" hidden>
        <span class="rest-timer__countdown" aria-live="polite"></span>
        <button class="rest-timer__cancel" type="button" aria-label="Cancel rest timer">cancel</button>
    </div>
`;

const TICK_MS = 250;

/**
 * Countdown timer shown next to the next pending set after the user marks a
 * set complete. Emits a typed `health:rest-timer-finish` event when the
 * countdown reaches zero, and hides itself on cancel.
 *
 * The source of truth is a `finishAtMs` epoch-milliseconds timestamp, not a
 * decrementing counter. Each tick reads `Date.now()` and derives "remaining"
 * from `(finishAt - now)`. This keeps the timer correct when the main thread
 * is busy or the tab is backgrounded (where `setInterval` callbacks are
 * throttled): a delayed tick still reads accurate elapsed time and fires the
 * finish event the moment `remainingMs <= 0`. `Date.now()` is used here
 * (instead of `Temporal.Now`) because this is millisecond stopwatch math,
 * not calendar/timezone logic — the "Temporal over Date" principle targets
 * the latter.
 */
export class RestTimer extends HTMLElement {
    private intervalId: ReturnType<typeof setInterval> | null = null;
    private finishAtMs: number | null = null;
    private container!: HTMLElement;
    private countdownNode!: HTMLElement;
    private cancelBtn!: HTMLButtonElement;

    constructor() {
        super();
        const shadow = this.attachShadow({ mode: 'open' });
        shadow.adoptedStyleSheets = [styles];
        shadow.appendChild(template.content.cloneNode(true));
        this.container = shadow.querySelector('.rest-timer') as HTMLElement;
        this.countdownNode = shadow.querySelector('.rest-timer__countdown') as HTMLElement;
        this.cancelBtn = shadow.querySelector('.rest-timer__cancel') as HTMLButtonElement;
        this.cancelBtn.addEventListener('click', () => this.cancel());
    }

    disconnectedCallback(): void {
        this.clearTickInterval();
    }

    /** Start (or restart) the countdown. Hidden when `durationSeconds <= 0`. */
    start(durationSeconds: number): void {
        this.clearTickInterval();
        if (!Number.isFinite(durationSeconds) || durationSeconds <= 0) {
            this.finishAtMs = null;
            this.hide();
            return;
        }
        const durationMs = Math.round(durationSeconds * 1000);
        this.finishAtMs = Date.now() + durationMs;
        this.render();
        this.container.hidden = false;
        this.intervalId = setInterval(() => this.tick(), TICK_MS);
    }

    /** Stop the timer immediately without firing the finish event. */
    cancel(): void {
        this.clearTickInterval();
        this.finishAtMs = null;
        this.hide();
    }

    /** Whether the timer is currently running. */
    isRunning(): boolean {
        return this.intervalId !== null;
    }

    private tick(): void {
        if (this.finishAtMs === null) return;
        const remainingMs = this.finishAtMs - Date.now();
        if (remainingMs <= 0) {
            this.clearTickInterval();
            this.finishAtMs = null;
            this.render();
            this.hide();
            this.dispatchEvent(createRestTimerFinishEvent());
            return;
        }
        this.render();
    }

    private render(): void {
        if (this.finishAtMs === null) {
            this.countdownNode.textContent = '0:00';
            return;
        }
        const remainingMs = this.finishAtMs - Date.now();
        const remainingSeconds = Math.max(0, Math.ceil(remainingMs / 1000));
        const minutes = Math.floor(remainingSeconds / 60);
        const seconds = remainingSeconds % 60;
        this.countdownNode.textContent = `${minutes}:${seconds.toString().padStart(2, '0')}`;
    }

    private hide(): void {
        this.container.hidden = true;
    }

    private clearTickInterval(): void {
        if (this.intervalId !== null) {
            clearInterval(this.intervalId);
            this.intervalId = null;
        }
    }
}

if (!customElements.get('rest-timer')) {
    customElements.define('rest-timer', RestTimer);
}
